import styled from "styled-components";
import { useState } from "react";
import { Link } from "react-router-dom";

export default function TelaExemplos() {
  const exemplos = [
    { sup: "Rápido", inf: "Devagar", supSound: "/Audios/Ciranda_voztoc_RAPIDO.wav", infSound: "/Audios/Ciranda_voztoc_DEVAGAR.wav" },
    { sup: "Forte", inf: "Fraco", supSound: "/sounds/forte.mp3", infSound: "/sounds/fraco.mp3" },
    { sup: "Agudo", inf: "Grave", supSound: "/sounds/agudo.mp3", infSound: "/sounds/grave.mp3" },
  ];

  const [variacao, setVariacao] = useState(0);

  const playSound = (soundPath) => {
    const audio = new Audio(soundPath);
    audio.play();
  };

  return (
    <>
      <Lateral>
        <button onClick={() => playSound(exemplos[variacao].supSound)}>Mais {exemplos[variacao].sup}</button>
        <button onClick={() => playSound(exemplos[variacao].infSound)}>Mais {exemplos[variacao].inf}</button>
      </Lateral>
      <Navegacao>
        <Link to={{ pathname: "/" }}>
          <button>Início</button>
        </Link>
        <button onClick={() => setVariacao((prev) => (prev < 2 ? prev + 1 : prev))}>Seguir</button>
      </Navegacao>
    </>
  );
}

const Lateral = styled.ul`
  position: absolute;
  right: 25px;
  top: 20%;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  height: 30vh;
`;

const Navegacao = styled.ul`
  position: absolute;
  bottom: 25px;
  width: 100%;
  display: flex;
  justify-content: space-between;
  padding: 20px;
`;
